#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Throttle the re-enrich/requeue backfill so it stops outpacing enrichment drain
(exit-0-safe). Discovers requeue/reenrich units, caps their batch via drop-ins and
slows their cadence; does NOT stop them (re-enrichment must continue, just bounded)."""
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"throttle","ts":int(time.time())}
try:
    units=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'").split()
    req=[u for u in units if 'requeue' in u.lower()]
    ree=[u for u in units if 'reenrich' in u.lower() or 're-enrich' in u.lower()]
    out["requeue_units"]=req; out["reenrich_units"]=ree
    done=[]
    # cap requeue batch + slow timer
    for u in req:
        if u.endswith('.service'):
            dd="/etc/systemd/system/%s.d"%u; os.makedirs(dd,exist_ok=True)
            open(dd+"/override.conf","w").write("[Service]\nEnvironment=ATLAS_REQUEUE_N=5000\n")
            done.append(u+":batch->5000")
        if u.endswith('.timer'):
            dd="/etc/systemd/system/%s.d"%u; os.makedirs(dd,exist_ok=True)
            open(dd+"/override.conf","w").write("[Timer]\nOnUnitInactiveSec=1800\n")
            done.append(u+":cadence->30min")
    # cap reenrich ladder batch
    for u in ree:
        if u.endswith('.service'):
            dd="/etc/systemd/system/%s.d"%u; os.makedirs(dd,exist_ok=True)
            open(dd+"/override.conf","w").write("[Service]\nEnvironment=REENRICH_BATCH=10000\n")
            done.append(u+":reenrich_batch->10000")
        if u.endswith('.timer'):
            dd="/etc/systemd/system/%s.d"%u; os.makedirs(dd,exist_ok=True)
            open(dd+"/override.conf","w").write("[Timer]\nOnUnitInactiveSec=1800\n")
            done.append(u+":cadence->30min")
    out["applied"]=done
    out["reload"]=sh("systemctl daemon-reload 2>&1; echo rc=$?")
    out["timers_now"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'requeue|reenrich' | awk '{print $5,$NF}'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/throttle.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"throttle","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
